    if n % 7 == 0:
        print(f"Found: {n}")
        break

# TODO: Print only odd numbers from 1 to 10
# Use continue to skip even numbers
for i in range(1, 11):
    if i % 2 == 0:
        continue   # skip even numbers
    print(i)

# Search for a target value
data = [3, 7, 12, 5, 19, 8, 14]
target = 19

for value in data:
    if value == target:
        print(f"Found {target} in the list.")
        break
else:
    # The else runs only if break was NOT triggered
    print(f"{target} was not found.")

# Try with a value not in the list
target2 = 99
for value in data:
    if value == target2:
        print(f"Found {target2} in the list.")
        break
else:
    print(f"{target2} was not found.")

